// src/assets/map.js
// This script loads the country data generated by build.js and renders an interactive Leaflet map.
// It highlights visited countries and shows a modal with related posts when a country is clicked.

document.addEventListener('DOMContentLoaded', () => {
  const mapContainer = document.getElementById('world-map');
  if (!mapContainer) return;

  // Initialise Leaflet map
  const map = L.map('world-map', {
    center: [20, 0], // Rough world centre
    zoom: 2,
    minZoom: 2,
    maxZoom: 5,
    attributionControl: false,
    zoomControl: true
  });

  // Use OpenStreetMap tiles (free & open)
  L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', {
    maxZoom: 19,
    attribution: '&copy; OpenStreetMap contributors'
  }).addTo(map);

  // Load country‑to‑posts mapping
  fetch(`${window.BASE_URL || ''}/data/countries.json`)
    .then(r => r.json())
    .then(countryMap => {
      // Load GeoJSON world borders (we can fetch a small world‑countries file from a CDN)
      // For simplicity we use a public GeoJSON source.
      fetch('https://raw.githubusercontent.com/datasets/geo-countries/master/data/countries.geojson')
        .then(r => r.json())
        .then(geoData => {
          const visitedStyle = {
            fillColor: '#ff7f50', // coral accent for visited countries
            weight: 1,
            color: '#333',
            fillOpacity: 0.6
          };
          const defaultStyle = {
            fillColor: '#e0e0e0',
            weight: 0.5,
            color: '#999',
            fillOpacity: 0.2
          };

          const onEachCountry = (feature, layer) => {
            const countryKey = feature.properties.ADMIN.toLowerCase().replace(/\s+/g, '-');
            if (countryMap[countryKey]) {
              layer.setStyle(visitedStyle);
              layer.on('mouseover', () => layer.setStyle({ fillOpacity: 0.9 }));
              layer.on('mouseout', () => layer.setStyle(visitedStyle));
              layer.on('click', () => showCountryModal(feature.properties.ADMIN, countryMap[countryKey]));
            } else {
              layer.setStyle(defaultStyle);
            }
          };

          L.geoJSON(geoData, { onEachFeature: onEachCountry }).addTo(map);
        })
        .catch(err => console.error('Failed to load GeoJSON:', err));
    })
    .catch(err => console.error('Failed to load country data:', err));

  // Modal handling
  const modal = document.getElementById('country-modal');
  const modalClose = document.getElementById('modal-close');
  const modalCountry = document.getElementById('modal-country');
  const modalPosts = document.getElementById('modal-posts');

  const showCountryModal = (countryName, posts) => {
    modalCountry.textContent = countryName;
    modalPosts.innerHTML = posts.map(p => `<li><a href="${p.url}">${p.title}</a> <small>(${p.date})</small></li>`).join('');
    modal.classList.remove('hidden');
  };

  modalClose.addEventListener('click', () => modal.classList.add('hidden'));
  // Close when clicking outside content
  modal.addEventListener('click', e => {
    if (e.target === modal) modal.classList.add('hidden');
  });
});
